    if (Double.isInfinite(x)) {
        return (x < 0) ? 0.0 : 1.0;
    }
    if (standardDeviation == 0) {
        return (x < mean) ? 0.0 : 1.0;
    }
    double z = (x - mean) / (standardDeviation * Math.sqrt(2.0));
    try {
        return 0.5 * (1.0 + Erf.erf(z));
